import{c as t,Q as s,j as e,m as n}from"./chunks/framework.Bhbi9jCp.js";const b=JSON.parse('{"title":"声音和图像怎么变成数据","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/02-声音和图像怎么变成数据.md","filePath":"mediaTechLearning/02-声音和图像怎么变成数据.md","lastUpdated":1780887690000}'),p={name:"mediaTechLearning/02-声音和图像怎么变成数据.md"};function i(l,a,d,o,h,r){return s(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="声音和图像怎么变成数据" tabindex="-1">声音和图像怎么变成数据 <a class="header-anchor" href="#声音和图像怎么变成数据" aria-label="Permalink to &quot;声音和图像怎么变成数据&quot;">​</a></h1><p>音视频工程第一步不是 FFmpeg,是把&quot;连续世界&quot;变成&quot;离散数字&quot;。声音是空气压力随时间变化,图像是光在二维平面上的分布。计算机不能存连续变化,只能按固定间隔采样。</p><blockquote><p>一句话先记住:<strong>音频是按时间采样的一串数字,视频是按时间排列的一串图片</strong>。后面所有编码、传输、播放,都在处理这两种序列。</p></blockquote><hr><h2 id="一、音频-空气压力变成-pcm" tabindex="-1">一、音频:空气压力变成 PCM <a class="header-anchor" href="#一、音频-空气压力变成-pcm" aria-label="Permalink to &quot;一、音频:空气压力变成 PCM&quot;">​</a></h2><p>麦克风采到的是电信号,声卡把它变成数字:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>空气振动 -&gt; 麦克风电压 -&gt; ADC -&gt; PCM 样本</span></span></code></pre></div><p>PCM 可以理解成最朴素的音频数据:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 0 个采样点:  120</span></span>
<span class="line"><span>第 1 个采样点:  180</span></span>
<span class="line"><span>第 2 个采样点:  160</span></span>
<span class="line"><span>第 3 个采样点: -40</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>常见参数:</p><table tabindex="0"><thead><tr><th>参数</th><th>例子</th><th>意思</th></tr></thead><tbody><tr><td>采样率</td><td>48000 Hz</td><td>每秒采多少个点</td></tr><tr><td>位深</td><td>16-bit</td><td>每个点用多少位表示</td></tr><tr><td>声道</td><td>1 / 2</td><td>单声道 / 双声道</td></tr><tr><td>编码</td><td>PCM / AAC / Opus</td><td>原始样本或压缩码流</td></tr></tbody></table><p>48kHz、16-bit、双声道 PCM 的码率:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>48000 x 16 x 2 = 1,536,000 bit/s = 1.536 Mbps</span></span></code></pre></div><p>这就是为什么语音通话不会直接传 PCM。Opus 可以把语音压到几十 kbps。</p><hr><h2 id="二、视频-一秒几十张图" tabindex="-1">二、视频:一秒几十张图 <a class="header-anchor" href="#二、视频-一秒几十张图" aria-label="Permalink to &quot;二、视频:一秒几十张图&quot;">​</a></h2><p>视频就是一串按时间排列的帧:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Frame 0  -&gt;  0ms</span></span>
<span class="line"><span>Frame 1  -&gt;  33ms</span></span>
<span class="line"><span>Frame 2  -&gt;  66ms</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>30fps 表示每秒 30 帧。每一帧本质是一张图片。最直观的 RGB 1080p 一帧:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1920 x 1080 x 3 bytes = 6.22 MB</span></span></code></pre></div><p>30fps 就是 186MB/s。原始视频不压缩没法传。</p><hr><h2 id="三、rgb-不适合直接压视频" tabindex="-1">三、RGB 不适合直接压视频 <a class="header-anchor" href="#三、rgb-不适合直接压视频" aria-label="Permalink to &quot;三、RGB 不适合直接压视频&quot;">​</a></h2><p>屏幕显示常用 RGB,但视频编码更常用 YUV:</p><table tabindex="0"><thead><tr><th>分量</th><th>含义</th></tr></thead><tbody><tr><td>Y</td><td>亮度</td></tr><tr><td>U / Cb</td><td>蓝色色度差</td></tr><tr><td>V / Cr</td><td>红色色度差</td></tr></tbody></table><p>人眼对亮度敏感,对颜色细节不那么敏感。所以可以保留完整 Y,降低 U/V 分辨率。最常见是 YUV 4:2:0:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>4 个像素共享一组 U/V 色度信息</span></span>
<span class="line"><span>亮度全保留,颜色降采样</span></span></code></pre></div><p>这不是玄学,是视频压缩的底层收益之一。</p><hr><h2 id="四、时间戳比帧号重要" tabindex="-1">四、时间戳比帧号重要 <a class="header-anchor" href="#四、时间戳比帧号重要" aria-label="Permalink to &quot;四、时间戳比帧号重要&quot;">​</a></h2><p>音视频不是只靠&quot;第几帧&quot;播放,而是靠时间戳:</p><table tabindex="0"><thead><tr><th>字段</th><th>作用</th></tr></thead><tbody><tr><td>PTS</td><td>什么时候显示 / 播放</td></tr><tr><td>DTS</td><td>什么时候送给解码器</td></tr></tbody></table><p>有 B 帧时,解码顺序和显示顺序可能不同。播放器要按 PTS 播,解码器要按 DTS 吃数据。</p><blockquote><p>很多音画不同步、HLS 分片异常、播放器拖动出问题,根因不是&quot;文件坏了&quot;,而是时间戳乱了。</p></blockquote><hr><h2 id="五、最小排查命令" tabindex="-1">五、最小排查命令 <a class="header-anchor" href="#五、最小排查命令" aria-label="Permalink to &quot;五、最小排查命令&quot;">​</a></h2><p>先别急着转码,先看流:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffprobe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -hide_banner</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffprobe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -show_streams</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -show_format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span></span></code></pre></div><p>重点看:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>codec_name</span></span>
<span class="line"><span>codec_type</span></span>
<span class="line"><span>width / height</span></span>
<span class="line"><span>pix_fmt</span></span>
<span class="line"><span>sample_rate</span></span>
<span class="line"><span>channels</span></span>
<span class="line"><span>duration</span></span>
<span class="line"><span>bit_rate</span></span>
<span class="line"><span>time_base</span></span></code></pre></div><p>看不懂 <code>ffprobe</code>,就等于闭眼修音视频。</p><hr><h2 id="六、踩坑提醒" tabindex="-1">六、踩坑提醒 <a class="header-anchor" href="#六、踩坑提醒" aria-label="Permalink to &quot;六、踩坑提醒&quot;">​</a></h2><ol><li><strong>把音频当成小事</strong>——会议里音频比视频重要。</li><li><strong>把 RGB 当视频内部格式</strong>——大多数视频编码链路会转到 YUV。</li><li><strong>忽略采样率转换</strong>——44.1kHz 和 48kHz 混用会引出同步问题。</li><li><strong>不知道 PTS / DTS</strong>——遇到 B 帧、切片、拖动时一定会踩坑。</li><li><strong>直接传原始帧</strong>——除非在本机内存里,否则一定会爆带宽。</li></ol><p>下一篇:<code>03-采样率、帧率、码率、分辨率.md</code>。</p>`,45)])])}const g=t(p,[["render",i]]);export{b as __pageData,g as default};
